'use client';

import { useState } from 'react';

type Tab = 'bunyols' | 'indumentaria' | 'genealogia' | 'premios' | 'playbacks' | 'sanciones';

const MEMBERS_INDUMENTARIA = [
    { name: 'María García', talla: 'M', traje: 'Fallera Mayor', seguro: true, estado: 'Completo' },
    { name: 'Ana Torres', talla: 'S', traje: 'Fallera', seguro: true, estado: 'Completo' },
    { name: 'Carlos Ruiz', talla: 'L', traje: 'Fallero', seguro: false, estado: 'Sin seguro' },
    { name: 'Lucía Fernández', talla: 'M', traje: 'Infantil', seguro: true, estado: 'Completo' },
    { name: 'Pablo Martínez', talla: 'XL', traje: 'Fallero', seguro: true, estado: 'En reparación' },
];

const FAMILY_TREE = [
    {
        family: 'García-Torres',
        members: [
            { name: 'Antonio García', role: 'Padre', years: 28, discount: '15%' },
            { name: 'Rosa Torres', role: 'Madre', years: 25, discount: '15%' },
            { name: 'María García', role: 'Hija', years: 8, discount: '10%' },
            { name: 'Pablo García', role: 'Hijo', years: 3, discount: '10%' },
        ],
    },
    {
        family: 'Martínez-López',
        members: [
            { name: 'Juan Martínez', role: 'Padre', years: 35, discount: '20%' },
            { name: 'Carmen López', role: 'Madre', years: 30, discount: '20%' },
            { name: 'Laura Martínez', role: 'Hija', years: 12, discount: '10%' },
        ],
    },
];

const PREMIOS = [
    { year: 2025, category: 'Falla Gran', prize: '2º Sección Especial', emoji: '🥈' },
    { year: 2025, category: 'Falla Infantil', prize: '1er Premio', emoji: '🥇' },
    { year: 2024, category: 'Falla Gran', prize: '3er Sección Especial', emoji: '🥉' },
    { year: 2024, category: 'Ingenio y Gracia', prize: '1er Premio', emoji: '🏆' },
    { year: 2023, category: 'Falla Gran', prize: '1er Sección Especial', emoji: '🥇' },
    { year: 2023, category: 'Falla Infantil', prize: '2º Premio', emoji: '🥈' },
    { year: 2022, category: 'Falla Gran', prize: '4º Sección Especial', emoji: '🏅' },
];

const PLAYBACK_ENSAYOS = [
    { date: '12/02', obra: 'Grease - Adaptación Fallera', asistentes: 18, sala: 'Casal - Planta 1' },
    { date: '14/02', obra: 'Grease - Ensayo Musical', asistentes: 22, sala: 'Casal - Salon' },
    { date: '19/02', obra: 'Grease - Ensayo General', asistentes: 25, sala: 'Casal - Planta 1' },
    { date: '22/02', obra: 'Grease - Vestuario', asistentes: 25, sala: 'Por confirmar' },
];

const SANCIONES = [
    { fallero: 'Andrés López', motivo: 'Inasistencia reunión 05/02', puntos: -5, fecha: '06/02/2026', estado: 'Vigente' },
    { fallero: 'Sara Vidal', motivo: 'No turno barra 01/02', puntos: -10, fecha: '02/02/2026', estado: 'Vigente' },
    { fallero: 'Miguel Sanz', motivo: 'Inasistencia plantà caseta', puntos: -3, fecha: '20/01/2026', estado: 'Cumplida' },
    { fallero: 'Eva Moreno', motivo: 'Impago cuota Diciembre', puntos: -8, fecha: '15/01/2026', estado: 'Vigente' },
];

export default function AdminPage() {
    const [activeTab, setActiveTab] = useState<Tab>('bunyols');
    const [bunyolYear, setBunyolYear] = useState(2026);
    const [bunyolJoinYear, setBunyolJoinYear] = useState(2010);

    const tabs: { key: Tab; label: string; icon: string }[] = [
        { key: 'bunyols', label: 'Bunyols', icon: '🍩' },
        { key: 'indumentaria', label: 'Indumentaria', icon: '👗' },
        { key: 'genealogia', label: 'Genealogía', icon: '🌳' },
        { key: 'premios', label: 'Premios', icon: '🏆' },
        { key: 'playbacks', label: 'Playbacks', icon: '🎭' },
        { key: 'sanciones', label: 'Sanciones', icon: '⚠️' },
    ];

    const bunyolYears = bunyolYear - bunyolJoinYear;
    const bunyolCategory = bunyolYears >= 25 ? 'Bunyol d\'Or' : bunyolYears >= 15 ? 'Bunyol de Plata' : bunyolYears >= 5 ? 'Bunyol de Bronze' : 'Sin bunyol';

    return (
        <div>
            <div className="page-header">
                <h1 className="page-title">🔥 Administración</h1>
                <p className="page-subtitle">Gestión interna de la comisión fallera</p>
            </div>

            <div className="tabs">
                {tabs.map((t) => (
                    <button key={t.key} className={`tab ${activeTab === t.key ? 'active' : ''}`} onClick={() => setActiveTab(t.key)}>
                        {t.icon} {t.label}
                    </button>
                ))}
            </div>

            {/* CALCULADORA BUNYOLS */}
            {activeTab === 'bunyols' && (
                <div className="animate-fade-in" style={{ maxWidth: 500 }}>
                    <div className="card">
                        <h3 style={{ marginBottom: 20, fontSize: 18 }}>🍩 Calculadora de Bunyols JCF</h3>
                        <div style={{ marginBottom: 16 }}>
                            <label style={{ fontSize: 13, color: 'var(--text-secondary)', display: 'block', marginBottom: 6 }}>Año de ingreso en la falla</label>
                            <input className="input" type="number" value={bunyolJoinYear} onChange={(e) => setBunyolJoinYear(Number(e.target.value))} />
                        </div>
                        <div style={{ marginBottom: 24 }}>
                            <label style={{ fontSize: 13, color: 'var(--text-secondary)', display: 'block', marginBottom: 6 }}>Año actual</label>
                            <input className="input" type="number" value={bunyolYear} onChange={(e) => setBunyolYear(Number(e.target.value))} />
                        </div>
                        <div className="stat-card" style={{ textAlign: 'center' }}>
                            <div className="stat-value" style={{ color: 'var(--accent-orange)' }}>{bunyolYears}</div>
                            <div className="stat-label">Años de fallero/a</div>
                            <div style={{ marginTop: 16 }}>
                                <span className={`badge ${bunyolYears >= 25 ? 'warning' : bunyolYears >= 15 ? 'info' : bunyolYears >= 5 ? 'purple' : 'danger'}`} style={{ fontSize: 14, padding: '8px 16px' }}>
                                    {bunyolYears >= 25 ? '🥇' : bunyolYears >= 15 ? '🥈' : bunyolYears >= 5 ? '🥉' : '❌'} {bunyolCategory}
                                </span>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* INDUMENTARIA */}
            {activeTab === 'indumentaria' && (
                <div className="animate-fade-in">
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
                        <input className="input" placeholder="🔍 Buscar fallero..." style={{ maxWidth: 300 }} />
                        <button className="btn btn-primary">+ Nueva Ficha</button>
                    </div>
                    <div className="card">
                        <table className="data-table">
                            <thead>
                                <tr>
                                    <th>Fallero/a</th>
                                    <th>Talla</th>
                                    <th>Tipo Traje</th>
                                    <th>Seguro</th>
                                    <th>Estado</th>
                                </tr>
                            </thead>
                            <tbody>
                                {MEMBERS_INDUMENTARIA.map((m, i) => (
                                    <tr key={i}>
                                        <td style={{ fontWeight: 500 }}>{m.name}</td>
                                        <td><span className="badge info">{m.talla}</span></td>
                                        <td>{m.traje}</td>
                                        <td>{m.seguro ? <span className="badge success">✓ Sí</span> : <span className="badge danger">✗ No</span>}</td>
                                        <td><span className={`badge ${m.estado === 'Completo' ? 'success' : m.estado === 'Sin seguro' ? 'danger' : 'warning'}`}>{m.estado}</span></td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* GENEALOGÍA */}
            {activeTab === 'genealogia' && (
                <div className="animate-fade-in">
                    {FAMILY_TREE.map((f) => (
                        <div key={f.family} className="card" style={{ marginBottom: 20 }}>
                            <h3 style={{ marginBottom: 16, display: 'flex', alignItems: 'center', gap: 8 }}>
                                🌳 Familia {f.family}
                            </h3>
                            <table className="data-table">
                                <thead>
                                    <tr>
                                        <th>Nombre</th>
                                        <th>Parentesco</th>
                                        <th>Años Fallero/a</th>
                                        <th>Dto. Familiar</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {f.members.map((m, i) => (
                                        <tr key={i}>
                                            <td style={{ fontWeight: 500 }}>{m.name}</td>
                                            <td>{m.role}</td>
                                            <td>{m.years} años</td>
                                            <td><span className="badge success">{m.discount}</span></td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    ))}
                </div>
            )}

            {/* PREMIOS */}
            {activeTab === 'premios' && (
                <div className="animate-fade-in">
                    <h3 className="section-title">🏆 Museo Digital de Premios</h3>
                    <div className="grid-3">
                        {PREMIOS.map((p, i) => (
                            <div key={i} className="card-glass" style={{ textAlign: 'center' }}>
                                <div style={{ fontSize: 48, marginBottom: 12 }}>{p.emoji}</div>
                                <div style={{ fontFamily: 'Outfit', fontSize: 28, fontWeight: 800, color: 'var(--accent-orange)' }}>{p.year}</div>
                                <div style={{ fontWeight: 600, marginTop: 8 }}>{p.prize}</div>
                                <div style={{ fontSize: 13, color: 'var(--text-secondary)', marginTop: 4 }}>{p.category}</div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* PLAYBACKS */}
            {activeTab === 'playbacks' && (
                <div className="animate-fade-in">
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
                        <h3 className="section-title" style={{ margin: 0 }}>🎭 Gestión de Ensayos</h3>
                        <button className="btn btn-primary">+ Nuevo Ensayo</button>
                    </div>
                    <div className="card" style={{ marginBottom: 24 }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 16, marginBottom: 16 }}>
                            <div style={{ fontSize: 40 }}>🎬</div>
                            <div>
                                <div style={{ fontWeight: 700, fontSize: 18 }}>Grease — Adaptación Fallera</div>
                                <div style={{ color: 'var(--text-secondary)', fontSize: 13 }}>Obra del año 2026 • 25 participantes</div>
                            </div>
                        </div>
                        <div className="progress-bar" style={{ marginBottom: 8 }}>
                            <div className="progress-fill" style={{ width: '60%' }} />
                        </div>
                        <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>60% preparado — 3 de 5 ensayos completados</div>
                    </div>
                    <div className="card">
                        <table className="data-table">
                            <thead>
                                <tr>
                                    <th>Fecha</th>
                                    <th>Sesión</th>
                                    <th>Asistentes</th>
                                    <th>Sala</th>
                                </tr>
                            </thead>
                            <tbody>
                                {PLAYBACK_ENSAYOS.map((e, i) => (
                                    <tr key={i}>
                                        <td style={{ fontWeight: 500 }}>{e.date}</td>
                                        <td>{e.obra}</td>
                                        <td><span className="badge info">👥 {e.asistentes}</span></td>
                                        <td>{e.sala}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* SANCIONES */}
            {activeTab === 'sanciones' && (
                <div className="animate-fade-in">
                    <div className="stats-grid" style={{ marginBottom: 24 }}>
                        <div className="stat-card">
                            <div className="stat-icon orange">⚠️</div>
                            <div className="stat-value">4</div>
                            <div className="stat-label">Sanciones Activas</div>
                        </div>
                        <div className="stat-card">
                            <div className="stat-icon green">✅</div>
                            <div className="stat-value">12</div>
                            <div className="stat-label">Cumplidas este año</div>
                        </div>
                        <div className="stat-card">
                            <div className="stat-icon purple">📊</div>
                            <div className="stat-value">-26</div>
                            <div className="stat-label">Puntos Descontados</div>
                        </div>
                    </div>
                    <div className="card">
                        <table className="data-table">
                            <thead>
                                <tr>
                                    <th>Fallero/a</th>
                                    <th>Motivo</th>
                                    <th>Puntos</th>
                                    <th>Fecha</th>
                                    <th>Estado</th>
                                </tr>
                            </thead>
                            <tbody>
                                {SANCIONES.map((s, i) => (
                                    <tr key={i}>
                                        <td style={{ fontWeight: 500 }}>{s.fallero}</td>
                                        <td>{s.motivo}</td>
                                        <td style={{ color: 'var(--accent-red)', fontWeight: 600 }}>{s.puntos}</td>
                                        <td>{s.fecha}</td>
                                        <td><span className={`badge ${s.estado === 'Vigente' ? 'danger' : 'success'}`}>{s.estado}</span></td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}
        </div>
    );
}
